Пример 16.1. Создать хеш-таблицу, использующую алгоритм размещения 
с линейной адресацией. 
void sv_add(int key, int m, int* H) 
{ 
    int i = abs(key % m); 
      while (H[i] != -1) { 
            i++; 
            if (i == m) i = 0; 
        } 
    H[i] = key; 
} 

int sv_seach(int key, int m, int *H) 
{ 
    int i = abs(key % m); 
    while (H[i] != -1) 
    { 
        if (H[i] == key) return i; 
           i++; 
           if (i == m) i = 0; 
    } 
    return -1; 
