TNode* search(TNode* p, int key) // Поиск по ключу 
{ 
 TNode* q = p; 
 while (q) 
 { 
  if (q->inf == key) return q; 
  if (key < q->inf) q = q->left; 
  else q = q->right; 
 } 
 return q; 
} 

